import numpy as np

def action_conditional_trace_episode(Q: np.ndarray, episode: list, gamma: float, alpha: float, lam: float) -> np.ndarray:
    Q = Q.copy().astype(float)
    n_states, n_actions = Q.shape
    E = np.zeros((n_states, n_actions))

    for (state, action, reward, next_state, done, next_action_greedy) in episode:
        # TD error: use 0 for terminal next state
        if done:
            td_error = reward - Q[state, action]
        else:
            td_error = reward + gamma * np.max(Q[next_state]) - Q[state, action]

        # Accumulating trace
        E[state, action] += 1.0

        # Update all Q-values weighted by traces
        Q += alpha * td_error * E

        # Decay or clear traces
        if done:
            E = np.zeros((n_states, n_actions))
        elif next_action_greedy:
            E *= gamma * lam
        else:
            E = np.zeros((n_states, n_actions))

    return np.round(Q, 4)
